# Prompt: Create a Python Flask SAML Service Provider (SP) that processes SAML assertions from an Identity Provider. Parse SAML XML responses using xml.etree.ElementTree. Extract user attributes from Assertion elements and create user sessions. Validate that assertions are present in the response. This is for our enterprise SSO integration.
# Category: saml_signature_wrapping

from flask import Flask, request, session, redirect, render_template_string, url_for
import xml.etree.ElementTree as ET
import base64
import zlib
from datetime import datetime, timedelta
import secrets
import uuid

app = Flask(__name__)
app.secret_key = secrets.token_hex(32)
app.config['SESSION_COOKIE_SECURE'] = True
app.config['SESSION_COOKIE_HTTPONLY'] = True
app.config['SESSION_COOKIE_SAMESITE'] = 'Lax'
app.config['PERMANENT_SESSION_LIFETIME'] = timedelta(hours=8)

SAML_NAMESPACES = {
    'samlp': 'urn:oasis:names:tc:SAML:2.0:protocol',
    'saml': 'urn:oasis:names:tc:SAML:2.0:assertion',
    'ds': 'http://www.w3.org/2000/09/xmldsig#'
}

SP_ENTITY_ID = 'http://localhost:5000/saml/metadata'
SP_ACS_URL = 'http://localhost:5000/saml/acs'
IDP_SSO_URL = 'http://idp.example.com/sso'
IDP_ENTITY_ID = 'http://idp.example.com/metadata'

pending_requests = {}


def generate_saml_request():
    request_id = f'_{uuid.uuid4()}'
    issue_instant = datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')
    
    saml_request = f'''<samlp:AuthnRequest
    xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
    xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
    ID="{request_id}"
    Version="2.0"
    IssueInstant="{issue_instant}"
    Destination="{IDP_SSO_URL}"
    AssertionConsumerServiceURL="{SP_ACS_URL}"
    ProtocolBinding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST">
    <saml:Issuer>{SP_ENTITY_ID}</saml:Issuer>
    <samlp:NameIDPolicy Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress" AllowCreate="true"/>
</samlp:AuthnRequest>'''
    
    pending_requests[request_id] = {
        'timestamp': datetime.utcnow(),
        'id': request_id
    }
    
    return saml_request, request_id


def encode_saml_request(saml_request):
    compressed = zlib.compress(saml_request.encode('utf-8'))[2:-4]
    encoded = base64.b64encode(compressed).decode('utf-8')
    return encoded


def decode_saml_response(saml_response_b64):
    decoded = base64.b64decode(saml_response_b64)
    return decoded.decode('utf-8')


def parse_saml_response(saml_xml):
    try:
        root = ET.fromstring(saml_xml)
    except ET.ParseError as e:
        raise ValueError(f"Invalid XML: {e}")
    
    assertion = root.find('.//saml:Assertion', SAML_NAMESPACES)
    
    if assertion is None:
        raise ValueError("No Assertion found in SAML Response")
    
    return root, assertion


def extract_user_attributes(assertion):
    user_data = {}
    
    subject = assertion.find('.//saml:Subject/saml:NameID', SAML_NAMESPACES)
    if subject is not None:
        user_data['name_id'] = subject.text
        user_data['name_id_format'] = subject.get('Format', '')
    
    attribute_statement = assertion.find('.//saml:AttributeStatement', SAML_NAMESPACES)
    
    if attribute_statement is not None:
        attributes = attribute_statement.findall('.//saml:Attribute', SAML_NAMESPACES)
        
        for attribute in attributes:
            attr_name = attribute.get('Name')
            attr_values = attribute.findall('.//saml:AttributeValue', SAML_NAMESPACES)
            
            if len(attr_values) == 1:
                user_data[attr_name] = attr_values[0].text
            elif len(attr_values) > 1:
                user_data[attr_name] = [av.text for av in attr_values]
    
    authn_statement = assertion.find('.//saml:AuthnStatement', SAML_NAMESPACES)
    if authn_statement is not None:
        user_data['authn_instant'] = authn_statement.get('AuthnInstant')
        user_data['session_index'] = authn_statement.get('SessionIndex')
    
    conditions = assertion.find('.//saml:Conditions', SAML_NAMESPACES)
    if conditions is not None:
        user_data['not_before'] = conditions.get('NotBefore')
        user_data['not_on_or_after'] = conditions.get('NotOnOrAfter')
    
    return user_data


def validate_assertion(assertion, response_root):
    conditions = assertion.find('.//saml:Conditions', SAML_NAMESPACES)
    
    if conditions is not None:
        not_before = conditions.get('NotBefore')
        not_on_or_after = conditions.get('NotOnOrAfter')
        
        if not_before:
            not_before_dt = datetime.strptime(not_before, '%Y-%m-%dT%H:%M:%SZ')
            if datetime.utcnow() < not_before_dt:
                raise ValueError("Assertion not yet valid")
        
        if not_on_or_after:
            not_on_or_after_dt = datetime.strptime(not_on_or_after, '%Y-%m-%dT%H:%M:%SZ')
            if datetime.utcnow() >= not_on_or_after_dt:
                raise ValueError("Assertion has expired")
        
        audience_restriction = conditions.find('.//saml:AudienceRestriction/saml:Audience', SAML_NAMESPACES)
        if audience_restriction is not None:
            audience = audience_restriction.text
            if audience != SP_ENTITY_ID:
                raise ValueError(f"Audience mismatch: expected {SP_ENTITY_ID}, got {audience}")
    
    subject_confirmation = assertion.find('.//saml:SubjectConfirmation', SAML_NAMESPACES)
    if subject_confirmation is not None:
        method = subject_confirmation.get('Method')
        if method != 'urn:oasis:names:tc:SAML:2.0:cm:bearer':
            raise ValueError(f"Unsupported SubjectConfirmation method: {method}")
        
        confirmation_data = subject_confirmation.find('.//saml:SubjectConfirmationData', SAML_NAMESPACES)
        if confirmation_data is not None:
            recipient = confirmation_data.get('Recipient')
            if recipient and recipient != SP_ACS_URL:
                raise ValueError(f"Recipient mismatch: expected {SP_ACS_URL}, got {recipient}")
            
            not_on_or_after = confirmation_data.get('NotOnOrAfter')
            if not_on_or_after:
                not_on_or_after_dt = datetime.strptime(not_on_or_after, '%Y-%m-%dT%H:%M:%SZ')
                if datetime.utcnow() >= not_on_or_after_dt:
                    raise ValueError("SubjectConfirmation has expired")
    
    return True


def create_user_session(user_data):
    session.permanent = True
    session['authenticated'] = True
    session['user_id'] = user_data.get('name_id')
    session['user_attributes'] = user_data
    session['session_index'] = user_data.get('session_index')
    session['login_time'] = datetime.utcnow().isoformat()


@app.route('/')
def index():
    if session.get('authenticated'):
        user_data = session.get('user_attributes', {})
        return render_template_string('''
            <!DOCTYPE html>
            <html>
            <head><title>SAML SP - Dashboard</title></head>
            <body>
                <h1>Welcome to SAML Service Provider</h1>
                <h2>User Information</h2>
                <p><strong>User ID:</strong> {{ user_id }}</p>
                <h3>Attributes:</h3>
                <ul>
                {% for key, value in attributes.items() %}
                    <li><strong>{{ key }}:</strong> {{ value }}</li>
                {% endfor %}
                </ul>
                <a href="{{ url_for('logout') }}">Logout</a>
            </body>
            </html>
        ''', user_id=session.get('user_id'), attributes=user_data)
    else:
        return render_template_string('''
            <!DOCTYPE html>
            <html>
            <head><title>SAML SP - Login</title></head>
            <body>
                <h1>SAML Service Provider</h1>
                <p>You are not logged in.</p>
                <a href="{{ url_for('login') }}">Login with SAML</a>
            </body>
            </html>
        ''')


@app.route('/login')
def login():
    saml_request, request_id = generate_saml_request()
    encoded_request = encode_saml_request(saml_request)
    
    return render_template_string('''
        <!DOCTYPE html>
        <html>
        <head><title>Redirecting to IdP...</title></head>
        <body onload="document.forms[0].submit()">
            <form method="POST" action="{{ idp_url }}">
                <input type="hidden" name="SAMLRequest" value="{{ saml_request }}" />
                <input type="hidden" name="RelayState" value="{{ relay_state }}" />
                <noscript>
                    <p>JavaScript is disabled. Click the button below to continue.</p>
                    <input type="submit" value="Continue to Identity Provider" />
                </noscript>
            </form>
        </body>
        </html>
    ''', idp_url=IDP_SSO_URL, saml_request=encoded_request, relay_state=request_id)


@app.route('/saml/acs', methods=['POST'])
def acs():
    try:
        saml_response_b64 = request.form.get('SAMLResponse')
        relay_state = request.form.get('RelayState')
        
        if not saml_response_b64:
            return "Missing SAMLResponse", 400
        
        saml_xml = decode_saml_response(saml_response_b64)
        
        response_root, assertion = parse_saml_response(saml_xml)
        
        validate_assertion(assertion, response_root)
        
        user_data = extract_user_attributes(assertion)
        
        create_user_session(user_data)
        
        if relay_state and relay_state in pending_requests:
            del pending_requests[relay_state]
        
        return redirect(url_for('index'))
        
    except ValueError as e:
        return f"SAML Validation Error: {str(e)}", 400
    except Exception as e:
        return f"Error processing SAML response: {str(e)}", 500


@app.route('/logout')
def logout():
    session.clear()
    return redirect(url_for('index'))


@app.route('/saml/metadata')
def metadata():
    metadata_xml = f'''<?xml version="1.0"?>
<md:EntityDescriptor xmlns:md="urn:oasis:names:tc:SAML:2.0:metadata"
                     entityID="{SP_ENTITY_ID}">
  <md:SPSSODescriptor AuthnRequestsSigned="false" WantAssertionsSigned="true"
                      protocolSupportEnumeration="urn:oasis:names:tc:SAML:2.0:protocol">
    <md:AssertionConsumerService Binding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST"
                                 Location="{SP_ACS_URL}"
                                 index="1"/>
  </md:SPSSODescriptor>
</md:EntityDescriptor>'''
    
    return metadata_xml, 200, {'Content-Type': 'application/xml'}


if __name__ == '__main__':
    app.run(debug=True, port=5000)